CREATE TABLE IF NOT EXISTS user_blocks(blocker_id TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,blocked_id TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,created_at TIMESTAMPTZ DEFAULT NOW(),PRIMARY KEY(blocker_id,blocked_id),CHECK(blocker_id<>blocked_id));
CREATE TABLE IF NOT EXISTS user_enforcements(id TEXT PRIMARY KEY,user_id TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,action TEXT NOT NULL CHECK(action IN ('warning','suspension','ban')),reason TEXT NOT NULL,starts_at TIMESTAMPTZ DEFAULT NOW(),expires_at TIMESTAMPTZ,created_by TEXT NOT NULL REFERENCES users(id),revoked_at TIMESTAMPTZ,revoked_by TEXT REFERENCES users(id));
CREATE TABLE IF NOT EXISTS moderation_appeals(id TEXT PRIMARY KEY,user_id TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,enforcement_id TEXT NOT NULL REFERENCES user_enforcements(id) ON DELETE CASCADE,statement TEXT NOT NULL,status TEXT DEFAULT 'pending',reviewed_by TEXT REFERENCES users(id),decision_reason TEXT,created_at TIMESTAMPTZ DEFAULT NOW(),reviewed_at TIMESTAMPTZ,UNIQUE(user_id,enforcement_id));
CREATE TABLE IF NOT EXISTS moderation_actions(id TEXT PRIMARY KEY,moderator_id TEXT NOT NULL REFERENCES users(id),action TEXT NOT NULL,target_type TEXT NOT NULL,target_id TEXT NOT NULL,reason TEXT NOT NULL,metadata JSONB DEFAULT '{}',created_at TIMESTAMPTZ DEFAULT NOW());
CREATE INDEX IF NOT EXISTS idx_enforcements_active ON user_enforcements(user_id,action,revoked_at,expires_at);
CREATE INDEX IF NOT EXISTS idx_appeals_queue ON moderation_appeals(status,created_at);
